import{_ as n,c as e,a,o as t}from"./app-BNbzGXAP.js";const o={};function p(i,s){return t(),e("div",null,s[0]||(s[0]=[a(`<h2 id="types" tabindex="-1"><a class="header-anchor" href="#types"><span>Types</span></a></h2><p><code>typeof</code> returns the type value in string.</p><h3 id="core-types" tabindex="-1"><a class="header-anchor" href="#core-types"><span>Core Types</span></a></h3><p>The core primitive types in TypeScript are all lowercase!</p><ul><li><code>number</code>: numbers are by default floats in both JS and TS, <code>+input</code> is equal to <code>parseFloat(input)</code></li><li><code>string</code></li><li><code>boolean</code></li><li><code>object</code>: object types are written almost like objects, but with key/type pairs.</li><li><code>Array</code>:</li><li><code>Tuple</code>(introduced in TS): <code>[number, string]</code> is a tuple type definition. <code>push</code> method is allowed for Tuple.</li><li><code>Enum</code>(introduced in TS): <code>enum { NEW, OLD }</code>, default is number type starting with 0 and automatically increment.</li><li><code>Any</code>(introduced in TS): takes away all the benefits that typescript gives you. Used as fallback.</li></ul><blockquote><p>When assigned <code>null</code> to variables of primitive types, the Typescript compiler will not complain.</p></blockquote><h3 id="object-type" tabindex="-1"><a class="header-anchor" href="#object-type"><span>Object Type</span></a></h3><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token comment">// typescript type inference for object type:</span></span>
<span class="line"><span class="token keyword">const</span> person <span class="token operator">=</span> <span class="token punctuation">{</span></span>
<span class="line">    name<span class="token operator">:</span> <span class="token string">&#39;Frost&#39;</span><span class="token punctuation">;</span></span>
<span class="line">    age<span class="token operator">:</span> <span class="token number">30</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// object type definition:</span></span>
<span class="line"><span class="token keyword">const</span> person<span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">    name<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span></span>
<span class="line">    age<span class="token operator">:</span> <span class="token builtin">number</span><span class="token punctuation">;</span></span>
<span class="line"> <span class="token punctuation">}</span> <span class="token operator">=</span> <span class="token punctuation">{</span></span>
<span class="line">    name<span class="token operator">:</span> <span class="token string">&#39;Frost&#39;</span><span class="token punctuation">;</span></span>
<span class="line">    age<span class="token operator">:</span> <span class="token number">30</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="union-intersection-types" tabindex="-1"><a class="header-anchor" href="#union-intersection-types"><span>Union &amp; Intersection Types</span></a></h3><p>Union types are types that accept more than 1 type:</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">let</span> input1<span class="token operator">:</span> <span class="token builtin">number</span> <span class="token operator">|</span> <span class="token builtin">string</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>Intersection types allow us to combine types.</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">type</span> <span class="token class-name">Admin</span> <span class="token operator">=</span> <span class="token punctuation">{</span></span>
<span class="line">  name<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span></span>
<span class="line">  privileges<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> <span class="token class-name">Employee</span> <span class="token operator">=</span> <span class="token punctuation">{</span></span>
<span class="line">  name<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span></span>
<span class="line">  startDate<span class="token operator">:</span> Date<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> <span class="token class-name">ElevatedEmployee</span> <span class="token operator">=</span> Admin <span class="token operator">&amp;</span> Employee<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>In the case of union types, intersection types output the members in common</li><li>In the case of object types, intersection types output the combination.</li></ul><h3 id="literal-types" tabindex="-1"><a class="header-anchor" href="#literal-types"><span>Literal Types</span></a></h3><p>Literal types are based on core types, like <code>string</code> or <code>number</code>, but with poticular value of those types, and often used together with union types:</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">let</span> resultConversion<span class="token operator">:</span> <span class="token string">&quot;as-number&quot;</span> <span class="token operator">|</span> <span class="token string">&quot;as-text&quot;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// this will popup compile errors.</span></span>
<span class="line"><span class="token keyword">if</span><span class="token punctuation">(</span>resultConversion <span class="token operator">===</span> <span class="token string">&#39;as-numbe&#39;</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="discriminated-unions" tabindex="-1"><a class="header-anchor" href="#discriminated-unions"><span>Discriminated Unions</span></a></h3><p>Build discriminated union by giving every interface an extra property(whatever name you want, typically &quot;kind&quot; or &quot;type&quot;),</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">interface</span> <span class="token class-name">Bird</span> <span class="token punctuation">{</span></span>
<span class="line">  type<span class="token operator">:</span> <span class="token string">&quot;bird&quot;</span><span class="token punctuation">;</span> <span class="token comment">// literal type in fact</span></span>
<span class="line">  flyingSpeed<span class="token operator">:</span> <span class="token builtin">number</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">interface</span> <span class="token class-name">Horse</span> <span class="token punctuation">{</span></span>
<span class="line">  type<span class="token operator">:</span> <span class="token string">&quot;horse&quot;</span><span class="token punctuation">;</span> <span class="token comment">// literal type in fact</span></span>
<span class="line">  runningSpeed<span class="token operator">:</span> <span class="token builtin">number</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> <span class="token class-name">Animal</span> <span class="token operator">=</span> Bird <span class="token operator">|</span> Horse<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">function</span> <span class="token function">moveAnimal</span><span class="token punctuation">(</span>animal<span class="token operator">:</span> Animal<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">let</span> speed<span class="token punctuation">;</span></span>
<span class="line">  <span class="token keyword">switch</span> <span class="token punctuation">(</span>animal<span class="token punctuation">.</span>type<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">case</span> <span class="token string">&quot;bird&quot;</span><span class="token operator">:</span></span>
<span class="line">      speed <span class="token operator">=</span> animal<span class="token punctuation">.</span>flyingSpeed<span class="token punctuation">;</span></span>
<span class="line">      <span class="token keyword">break</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">case</span> <span class="token string">&quot;horse&quot;</span><span class="token operator">:</span></span>
<span class="line">      speed <span class="token operator">=</span> animal<span class="token punctuation">.</span>runningSpeed<span class="token punctuation">;</span></span>
<span class="line">      <span class="token keyword">break</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  <span class="token builtin">console</span><span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;Moving with speed: &quot;</span> <span class="token operator">+</span> speed<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token function">moveAnimal</span><span class="token punctuation">(</span><span class="token punctuation">{</span> type<span class="token operator">:</span> <span class="token string">&quot;bird&quot;</span><span class="token punctuation">,</span> flyingSpeed<span class="token operator">:</span> <span class="token number">10</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="type-aliases" tabindex="-1"><a class="header-anchor" href="#type-aliases"><span>Type Aliases</span></a></h3><p><code>type</code> keyword in Typescript is used to set type aliases:</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token comment">// use with union types</span></span>
<span class="line"><span class="token keyword">type</span> <span class="token class-name">Combinable</span> <span class="token operator">=</span> <span class="token builtin">number</span> <span class="token operator">|</span> <span class="token builtin">string</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">// use with literal types</span></span>
<span class="line"><span class="token keyword">type</span> <span class="token class-name">ConversionDescriptor</span> <span class="token operator">=</span> <span class="token string">&quot;as-number&quot;</span> <span class="token operator">|</span> <span class="token string">&quot;as-text&quot;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">// use with object type</span></span>
<span class="line"><span class="token class-name"><span class="token keyword">type</span></span> User <span class="token operator">=</span> <span class="token punctuation">{</span></span>
<span class="line">  name<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span></span>
<span class="line">  age<span class="token operator">:</span> <span class="token builtin">number</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="void-type-never-type" tabindex="-1"><a class="header-anchor" href="#void-type-never-type"><span>Void Type &amp; Never Type</span></a></h3><p><code>undefined</code> is not valid return type for functions in Typescript, because Typescript would expect the function to have a <code>return</code> statement, just not return a value. <code>void</code> means the function does not return anything, it is allowed that the function does not have a <code>return</code> statement.</p><p><code>never</code> type can be used as another return type for functions that never return anything, essentially throw errors or in a infinite loop.</p><h3 id="functions-as-types" tabindex="-1"><a class="header-anchor" href="#functions-as-types"><span>Functions as Types</span></a></h3><p><code>Function</code> type allows to assign a function signature to variables, which is quite simular to delegates in C#.</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token comment">// define a function type that takes 2 number type parameters and return a number</span></span>
<span class="line"><span class="token keyword">let</span> <span class="token function-variable function">combineValues</span><span class="token operator">:</span> <span class="token punctuation">(</span>a<span class="token operator">:</span> <span class="token builtin">number</span><span class="token punctuation">,</span> b<span class="token operator">:</span> <span class="token builtin">number</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token builtin">number</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">// used together with type alias</span></span>
<span class="line"><span class="token keyword">type</span> <span class="token class-name">AddFunction</span> <span class="token operator">=</span> <span class="token punctuation">(</span>a<span class="token operator">:</span> <span class="token builtin">number</span><span class="token punctuation">,</span> b<span class="token operator">:</span> <span class="token builtin">number</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token builtin">number</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">// used together with callback functions</span></span>
<span class="line"><span class="token keyword">function</span><span class="token punctuation">(</span>a<span class="token operator">:</span> <span class="token builtin">number</span><span class="token punctuation">,</span> b<span class="token operator">:</span> <span class="token builtin">number</span><span class="token punctuation">,</span> <span class="token function-variable function">cb</span><span class="token operator">:</span> <span class="token punctuation">(</span>num<span class="token operator">:</span> <span class="token builtin">number</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token keyword">void</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>When function type is used with a callback function, the <code>void</code> means the function will not use the returned value, it does not restrict that the function cannot have a <code>return</code> statement.</p></blockquote><h3 id="unknown-type" tabindex="-1"><a class="header-anchor" href="#unknown-type"><span>Unknown Type</span></a></h3><p><code>Any</code> is the most flexible type in Typescript which basically disables all type checking. <code>unknown</code> is a bit more restrictive than <code>Any</code> type, Typescript will have type checkings on it before assign it to another variable with clear type:</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">let</span> userInput<span class="token operator">:</span> <span class="token builtin">unknown</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">let</span> userName<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">userInput <span class="token operator">=</span> <span class="token number">5</span><span class="token punctuation">;</span></span>
<span class="line">userName <span class="token operator">=</span> userInput<span class="token punctuation">;</span> <span class="token comment">// tsc will complain</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="classes-interfaces" tabindex="-1"><a class="header-anchor" href="#classes-interfaces"><span>Classes &amp; Interfaces</span></a></h2><h3 id="classes" tabindex="-1"><a class="header-anchor" href="#classes"><span>Classes</span></a></h3><p>Class exists since ES6, typescript supports it and extends a few use cases.</p><ul><li>Consturctor: <code>constructor</code> is the syntax sugar which is called when you call the <code>new SimpleClass()</code> to create class instance.</li><li><code>this</code> keyword: refers to the concrete instance of the class in methods. However, <code>this</code> typically refers to the object that is responsible to call methods. We can declare <code>this:Department</code> in method parameters, so that Typescript ensures that <code>this</code> keyword inside a method should always refer to an instance of type <code>Department</code>.</li><li><code>public</code> is the default modifer for class members.</li><li>Shorthand Initialization: <code>constructor(private id: string, private name: string){};</code>: declare class fields as constructor parameters.</li><li><code>readonly</code> modifier: it makes sure the field can be only written during initialization.</li><li><code>extends</code> keyword allows class to inherit from another class. One class can only inherit from one parent class. <ul><li>Always call <code>super()</code> first in the inherited class&#39;s own constructors.</li><li>With <code>es7</code>, we can directly use property definition in class, no need to call <code>super</code>.</li></ul></li><li>Override: <ul><li>Define the same method signature in derived class to override the implementation of that method in base class.</li><li>use <code>protected</code> keyword to allow derived classes to have access.</li></ul></li><li>Getters &amp; Setters: <ul><li><code>get</code> keyword is used to create a getter. Getters are defined in method signature, while it is accessed like properties. Getter is by default public.</li><li><code>set</code> keyword is used to create a setter, but it takes a <code>value</code> argument.</li></ul></li><li>Abstract Class: <code>abstract</code> keyword can only be used in abstract class to define abstract members.</li></ul><h3 id="interfaces" tabindex="-1"><a class="header-anchor" href="#interfaces"><span>Interfaces</span></a></h3><ul><li><code>interface</code> only exists in Typescript</li><li>Interfaces define a structure of objects.</li><li>Typically used as a custom type</li><li>A class can implement an interface by using <code>implements</code> keyword, while it can not implement a custom type in the early days due to historical reasons.</li><li>Interface can also be used to define a function type: <code>interface AddFn { (a: number, b: number): number; }</code>, but it is more common to use custom type to define function types.</li><li>Specify optional properties/parameters/methods by adding <code>?</code> after the property name. Default value of optional properties is <code>undefined</code>.</li><li>Interface is purely a development feature for writing better codes.</li></ul><h3 id="type-alias-vs-interfaces" tabindex="-1"><a class="header-anchor" href="#type-alias-vs-interfaces"><span>Type Alias vs. Interfaces</span></a></h3><ul><li>Interfaces are basically a way to describe data shapes, for example, an object.</li><li>Type is a definition of a type of data, for example, a union, primitive, intersection, tuple, or any other type.</li></ul><h4 id="declaration-merging" tabindex="-1"><a class="header-anchor" href="#declaration-merging"><span>Declaration Merging</span></a></h4><p>One thing that’s possible to do with interfaces but are not with types is declaration merging.</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">interface</span> <span class="token class-name">Song</span> <span class="token punctuation">{</span></span>
<span class="line">  artistName<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">interface</span> <span class="token class-name">Song</span> <span class="token punctuation">{</span></span>
<span class="line">  songName<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">const</span> song<span class="token operator">:</span> Song <span class="token operator">=</span> <span class="token punctuation">{</span></span>
<span class="line">  artistName<span class="token operator">:</span> <span class="token string">&quot;Freddie&quot;</span><span class="token punctuation">,</span></span>
<span class="line">  songName<span class="token operator">:</span> <span class="token string">&quot;The Chain&quot;</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="extends-and-implements" tabindex="-1"><a class="header-anchor" href="#extends-and-implements"><span>Extends and Implements</span></a></h4><p>In TypeScript, we can easily extend and implement interfaces. This is not possible with types though.</p><h4 id="what-should-i-use" tabindex="-1"><a class="header-anchor" href="#what-should-i-use"><span>What should I use?</span></a></h4><ul><li>Interfaces are better when you need to define a new object or method of an object.</li><li>Types are better when you need to create function types.</li></ul><h2 id="type-guards" tabindex="-1"><a class="header-anchor" href="#type-guards"><span>Type Guards</span></a></h2><h3 id="typeof-keyword" tabindex="-1"><a class="header-anchor" href="#typeof-keyword"><span>&quot;typeof&quot; keyword</span></a></h3><p><code>typeof</code> is used to check primitive types. However, using <code>typeof</code> to check custom types always return <code>Object</code>.</p><h3 id="in-keyword" tabindex="-1"><a class="header-anchor" href="#in-keyword"><span>&quot;in&quot; keyword</span></a></h3><p>Instead, we use <code>in</code> keyword for type guards of custom types.</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token comment">// The way to check if a property exsits in an object at runtime.</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token string">&quot;privileges&quot;</span> <span class="token keyword">in</span> emp<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token builtin">console</span><span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;Privileges: &quot;</span> <span class="token operator">+</span> emp<span class="token punctuation">.</span>privileges<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="instanceof-keyword" tabindex="-1"><a class="header-anchor" href="#instanceof-keyword"><span>&quot;instanceof&quot; keyword</span></a></h3><p>Another type guard method is to use <code>instanceof</code> keyword:</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">type</span> <span class="token class-name">Vehicle</span> <span class="token operator">=</span> Car <span class="token operator">|</span> Truck<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">const</span> v1 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Car</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">const</span> v2 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Truck</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">function</span> <span class="token function">useVehicle</span><span class="token punctuation">(</span>vehicle<span class="token operator">:</span> Vehicle<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  vehicle<span class="token punctuation">.</span><span class="token function">drive</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token keyword">if</span> <span class="token punctuation">(</span>vehicle <span class="token keyword">instanceof</span> <span class="token class-name">Truck</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    vehicle<span class="token punctuation">.</span><span class="token function">loadCargo</span><span class="token punctuation">(</span><span class="token number">1000</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><code>instanceof</code> can be used for <code>class</code>. However, <code>instanceof</code> can not be used to check <code>interface</code>, because interfaces are not translated into any javascript code.</p></blockquote><h3 id="type-casting" tabindex="-1"><a class="header-anchor" href="#type-casting"><span>Type Casting</span></a></h3><p>Typescript has no idea what type of the <code>element</code> is:</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">const</span> element <span class="token operator">=</span> document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&quot;user-input&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">element<span class="token punctuation">.</span>value <span class="token operator">=</span> <span class="token string">&quot;Hi there!&quot;</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="ttype-before-the-variable" tabindex="-1"><a class="header-anchor" href="#ttype-before-the-variable"><span><code>&lt;TType&gt;</code> before the variable</span></a></h4><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">const</span> element <span class="token operator">=</span> <span class="token operator">&lt;</span>HTMLInputElement<span class="token operator">&gt;</span>document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&quot;user-input&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">element<span class="token punctuation">.</span>value <span class="token operator">=</span> <span class="token string">&quot;Hi there!&quot;</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="as-keyword-after-the-variable" tabindex="-1"><a class="header-anchor" href="#as-keyword-after-the-variable"><span>&quot;as&quot; keyword after the variable</span></a></h4><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">const</span> element <span class="token operator">=</span> document<span class="token punctuation">.</span><span class="token function">getElementById</span><span class="token punctuation">(</span><span class="token string">&quot;user-input&quot;</span><span class="token punctuation">)</span> <span class="token keyword">as</span> HTMLInputElement<span class="token punctuation">;</span></span>
<span class="line">element<span class="token punctuation">.</span>value <span class="token operator">=</span> <span class="token string">&quot;Hi there!&quot;</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="index-properties" tabindex="-1"><a class="header-anchor" href="#index-properties"><span>Index Properties</span></a></h2><p>Index types allow us to create objects which are more flexible regarding the properties they might hold.</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">interface</span> <span class="token class-name">ErrorContainer</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token comment">// { email: &#39;Not a valid email&#39;, user: &#39;X&#39; }</span></span>
<span class="line">  <span class="token punctuation">[</span>key<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">]</span><span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Every property added the key must be a string and the value must be a string.</p><h2 id="function-overloads" tabindex="-1"><a class="header-anchor" href="#function-overloads"><span>Function Overloads</span></a></h2><p>To define function overloads:</p><ul><li>Same function name</li><li>Different parameter amount, types and return type.</li></ul><h2 id="optional-chaining" tabindex="-1"><a class="header-anchor" href="#optional-chaining"><span>Optional Chaining</span></a></h2><p>In Javascript. we often do something like <code>fetchedUserData.job &amp;&amp; fetchedUserData.job.title</code> to securely access <code>job.title</code> in case it does exist. In typescript, we can use <code>fetchedUserData.job?.title</code> as the equivalent.</p><h3 id="nullish-coalescing" tabindex="-1"><a class="header-anchor" href="#nullish-coalescing"><span>Nullish Coalescing</span></a></h3><p><code>const storeData = userInput ?? &#39;DEFAULT&#39;;</code>: means only return &quot;DEFAULT&quot; only when <code>userInput</code> is <code>null</code> or <code>undefined</code>.</p><h2 id="generic-types" tabindex="-1"><a class="header-anchor" href="#generic-types"><span>Generic Types</span></a></h2><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">function</span> <span class="token generic-function"><span class="token function">merge</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token constant">T</span><span class="token punctuation">,</span> <span class="token constant">U</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span>objA<span class="token operator">:</span> <span class="token constant">T</span><span class="token punctuation">,</span> objB<span class="token operator">:</span> <span class="token constant">B</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="constraints" tabindex="-1"><a class="header-anchor" href="#constraints"><span>Constraints</span></a></h3><p>Use <code>extends</code> to set constraints for type arguments.</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">function</span> <span class="token generic-function"><span class="token function">merge</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token constant">T</span> <span class="token keyword">extends</span> object<span class="token punctuation">,</span> <span class="token constant">U</span> <span class="token keyword">extends</span> object<span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span>objA<span class="token operator">:</span> <span class="token constant">T</span><span class="token punctuation">,</span> objB<span class="token operator">:</span> <span class="token constant">B</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="keyof-constraint" tabindex="-1"><a class="header-anchor" href="#keyof-constraint"><span>&quot;keyof&quot; Constraint</span></a></h4><p>Type argument <code>U</code> should be one of existing key of type <code>T</code>:</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code class="language-typescript"><span class="line"><span class="token keyword">function</span> <span class="token generic-function"><span class="token function">extractAndConvert</span><span class="token generic class-name"><span class="token operator">&lt;</span><span class="token constant">T</span> <span class="token keyword">extends</span> object<span class="token punctuation">,</span> <span class="token constant">U</span> <span class="token keyword">extends</span> <span class="token keyword">keyof</span> <span class="token constant">T</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="typescript-built-in-generic-utility-types" tabindex="-1"><a class="header-anchor" href="#typescript-built-in-generic-utility-types"><span>Typescript built-in generic utility types</span></a></h3><p>These types only exsits in typescript world.</p><ul><li><code>Partial&lt;T&gt;</code></li><li><code>Readonly&lt;T&gt;</code></li><li>...</li></ul><h2 id="decorators" tabindex="-1"><a class="header-anchor" href="#decorators"><span>Decorators</span></a></h2><ul><li>Decorators execute when defining classes. It does not execute at runtime.</li><li>Use <code>@</code> to use the decorators</li><li>Decorator factories runs in top-bottom order, while decorators run in bottom-top order.</li></ul><h3 id="class-decorators" tabindex="-1"><a class="header-anchor" href="#class-decorators"><span>Class Decorators</span></a></h3><ul><li>Class decorators are functions with one argument of target constructor.</li><li>Class decorators can return a new class to extend the original class with extra logic.</li></ul><h3 id="property-decorators" tabindex="-1"><a class="header-anchor" href="#property-decorators"><span>Property Decorators</span></a></h3><p>Property decorator receives 2 arguments:</p><ul><li>target: <strong>prototype of the object</strong> if attached to an instance property, or <strong>the constructor function</strong> if attached to a static property</li><li>property name: property name of <code>string</code> or <code>symbol</code> type.</li></ul><h3 id="accessor-decorators" tabindex="-1"><a class="header-anchor" href="#accessor-decorators"><span>Accessor Decorators</span></a></h3><p>Accessor decorator receives 3 arguments:</p><ul><li>target: <strong>prototype of the object</strong> if attached to an instance accessor, or <strong>the constructor function</strong> if attached to a static accessor</li><li>name: name of the accessor itself of type <code>string</code> or <code>symbol</code>.</li><li>property descriptor: of Typescript built-in type <code>PropertyDescriptor</code>.</li></ul><h3 id="methods-decorators" tabindex="-1"><a class="header-anchor" href="#methods-decorators"><span>Methods Decorators</span></a></h3><p>Method decorator receives 3 arguments:</p><ul><li>target: <strong>prototype of the object</strong> if attached to an instance method, or <strong>the constructor function</strong> if attached to a static method</li><li>name: name of the method of type <code>string</code> or <code>symbol</code>.</li><li>property descriptor: of Typescript built-in type <code>PropertyDescriptor</code>.</li></ul><p>Accessor and methods decorators can return a new <code>PropertyDescriptor</code> to replace the original one.</p><h3 id="parameter-decorators" tabindex="-1"><a class="header-anchor" href="#parameter-decorators"><span>Parameter Decorators</span></a></h3><p>Parameter decorator receives 3 arguments:</p><ul><li>target: <strong>prototype of the object</strong> if attached to an instance method, or <strong>the constructor function</strong> if attached to a static method</li><li>name: name of the method in which the parameter is used, of type <code>string</code> or <code>symbol</code>.</li><li>position of the parameter: of type <code>number</code>, index starting with 0.</li></ul><h2 id="typescript-compiler" tabindex="-1"><a class="header-anchor" href="#typescript-compiler"><span>Typescript Compiler</span></a></h2><h3 id="watch-mode" tabindex="-1"><a class="header-anchor" href="#watch-mode"><span>Watch mode:</span></a></h3><p>Use <code>tsc app.ts --watch/-w</code> to watch changes for a single file.</p><h3 id="compile-entire-project" tabindex="-1"><a class="header-anchor" href="#compile-entire-project"><span>Compile entire project:</span></a></h3><p><code>tsc --init</code> creates a <code>tsconfig.json</code> file for the working directory and considers it as a typescript project, run <code>tsc</code> will compile all the files under the folder/sub-folders.</p><h3 id="tsconfig-json" tabindex="-1"><a class="header-anchor" href="#tsconfig-json"><span>tsconfig.json</span></a></h3><p><code>tsconfig.json</code> tells typescript how the compiler behaves.</p><ul><li><code>&quot;exclude&quot;: [&quot;node_modules&quot;]</code>: accept an array of files and folders to be excluded. It accepts wildcard pattern. <code>node_modules</code> is excluded by default.</li><li><code>&quot;include&quot;: []</code>: accept an array of files and folders to be included. If it is set, everything not covered by <code>include</code> will not get compiled.</li><li><code>&quot;files&quot;: []</code>: allows to point the individual files of specific paths.</li></ul><h4 id="compileroptions-section" tabindex="-1"><a class="header-anchor" href="#compileroptions-section"><span>compilerOptions section</span></a></h4><ul><li><code>&quot;target&quot;: &quot;es5&quot;</code>: tells typescript in which ES version you want to compile the code to. <code>&quot;es5&quot;</code> is the default value.</li><li><code>&quot;lib&quot;: [&quot;dom&quot;, &quot;es6&quot;, &quot;dom.iterable&quot;, &quot;scripthost&quot;]</code>: allows to specify which default objects and features typescript knows. Typescript does not know anything about <code>DOM</code> objects by default. However the default value depends on the <code>target</code> option. For example, for <code>es6</code>, it by default includes all the features that are globally available in ES6, and it assumes that all DOM APIs are available. Basically the default libs allow your compiled javascript run in the browser.</li><li><code>&quot;allowJs&quot;: false</code>: allow to include javascript files in the complaination</li><li><code>&quot;checkJs&quot;: false</code>: will not compile javascript files but will check syntax and report errors.</li><li><code>&quot;sourceMap&quot;: false</code>: helps with debugging. If set to <code>true</code>, the compiler will also generate <code>.js.map</code> file as well, which acts as a bridge between javascript and typescript. The browser will also load the typescript file and allow debugging.</li><li><code>&quot;outDir&quot;: &quot;./&quot;</code>: tell the typescript compiler where the created javascript files should be stored.</li><li><code>&quot;rootDir&quot;: &quot;./&quot;</code>: make sure typescript does not look into others folders.</li><li><code>&quot;removeComments&quot;: false</code>: will remove any comments after compilation.</li><li><code>&quot;noEmit&quot;: false</code>: does not generate any javascript files, like dry run.</li><li><code>&quot;noEmitOnError&quot;: false</code>: if set to <code>true</code>, typescript will stop generating any outputs if any error detected.</li><li><code>&quot;strict&quot;: false</code>: If set to <code>true</code>, it enables all following strict type-checking options: <ul><li><code>&quot;noImplictAny&quot;: false</code>: If set to <code>true</code>, it ensures that we have to be clear about the types of the parameters that in no way can be inferred.</li><li><code>&quot;strictNullChecks&quot;: false</code>: If set to <code>false</code>, the compiler will not complain a potential null value variable.</li><li><code>&quot;strictFunctionTypes&quot;:</code>:</li><li><code>&quot;strictBindCallApply&quot;:</code>: If set to <code>true</code>, it checks if it makes sense(match arguments) of the arguments you passed to <code>bind</code>, <code>call</code> and <code>apply</code> functions.</li><li><code>&quot;strictPropertyInitialization&quot;: </code>:</li><li><code>&quot;noImplicitThis&quot;: </code>:</li><li><code>&quot;alwaysStrict&quot;: </code>: If set to <code>true</code>, it controls that the generated javascript code always use &quot;strict&quot; mode.</li></ul></li><li><code>&quot;noUnusedLocals&quot;: false</code>: If set to <code>true</code>, the compiler will give warnings on unused <strong>local</strong>(like within functions) variables, stops compiling.</li><li><code>&quot;noUnusedParameters&quot;: false</code>: If set to <code>true</code>, the compiler will give warnings on unused function <strong>parameters</strong>, stops compiling.</li><li><code>&quot;noImplicitReturns&quot;: false</code>: If set to <code>true</code>, every path of a function is forced to have a <code>return</code> statement, otherwise it will be considered as errors.</li></ul><h3 id="debugging-with-visual-studio-code" tabindex="-1"><a class="header-anchor" href="#debugging-with-visual-studio-code"><span>Debugging with Visual Studio Code</span></a></h3><ol><li>Install <code>Debugger for Chrome</code> extension in VS Code.</li><li>Enable <code>&quot;sourceMap&quot;: true</code> option in <code>tsconfig.ts</code> file.</li><li>In your project, click debug and select &quot;Chrome&quot; as the environment.</li><li>In <code>.vscode/launch.json</code> file, make sure the <code>url</code> value points to the right local url for you local web server.</li><li>Set some break points, and click Start Debugging.</li></ol><h3 id="declaration-files" tabindex="-1"><a class="header-anchor" href="#declaration-files"><span>Declaration Files</span></a></h3><p>Use <code>declare module</code> to define type definitions for packages that do not come with built-in types. See details <a href="https://www.typescriptlang.org/docs/handbook/declaration-files/introduction.html" target="_blank" rel="noopener noreferrer">here</a>.</p>`,118)]))}const l=n(o,[["render",p]]),r=JSON.parse('{"path":"/posts/webfrontend/web-frontend-devnotes-typescript/","title":"Web Front-end Notes - Typescript","lang":"zh-CN","frontmatter":{"title":"Web Front-end Notes - Typescript","date":"2020-09-07T09:21:58.000Z","description":"Basics of Typescript","excerpt":"Basics of Typescript","category":["WebFrontend"],"tag":["typescript","javascript"]},"git":{"updatedTime":1772897300000,"contributors":[{"name":"Frost He","username":"","email":"frosthe@qq.com","commits":3}],"changelog":[{"hash":"d7c833874cf63a93565de131aaea7abd35fb7629","time":1772897300000,"email":"frosthe@qq.com","author":"Frost He","message":"修复了一下 description"},{"hash":"9084b9be2b5259bd761dea3af5664f5e729d3efb","time":1772892199000,"email":"frosthe@qq.com","author":"Frost He","message":"修复了 build 错误"},{"hash":"ffa4807bd7d8fdbc3c457d61dcbe1be8e2744be4","time":1772706409000,"email":"frosthe@qq.com","author":"Frost He","message":"博客迁移初步完成"}]},"filePathRelative":"posts/webfrontend/web-frontend-devnotes-typescript/index.md"}');export{l as comp,r as data};
